-- Top 500 public vocabulary content v1, part 1.
-- Self-authored learner definitions and examples for words 201-220.
-- Phonetics are bootstrap IPA values and remain tracked for manual review.

UPDATE vocabulary_pronunciations SET phonetic_source = 'manual-curation-pending-review', updated_at = CURRENT_TIMESTAMP WHERE accent IN ('us', 'uk') AND vocabulary_id IN (SELECT id FROM core_vocabulary WHERE publish_status = 'active' AND learning_priority <= 500);

UPDATE core_vocabulary SET word = 'money', meaning_zh = '金钱', definition_en = 'coins, notes, or digital value used to buy things', primary_part_of_speech = 'noun', phonetic_us = '/ˈməni/', phonetic_uk = '/ˈməni/', updated_at = CURRENT_TIMESTAMP WHERE id = 'money';
